mapper.select:
select distinct a.id, a.title, a.summary, a.cover, a.category, a.content, a.published_at, a.updated_at, a.views, a.likes, a.comments from article a
inner join article_tag at on at.article_id = a.id
where a.status = 'PUBLISHED'
and at.tag_id = #{tagId}
order by a.published_at desc, a.id desc limit #{limit} offset #{offset}
